    def __init__(self):
        QMainWindow.__init__(self)
        ParameterManager.__init__(self, action_list=('search', 'save', 'load'))
        ActionManager.__init__(self)

        self.setWindowTitle("SERVAL Acquisition")
        self.setMinimumSize(1200, 800)
        self.resize(1600, 1000)

        # Core objects
        self.serval = SERVALController()
        self.histogram = HistogramController()
        self.pipeline_thread = None

        self._gui_logger = get_logger('SERVAL.GUI')
        # self._gui_logger.setLevel("DEBUG")
        # State
        self.is_acquiring = False
        self._is_recording = False
        self._display_mode = 'events'   # 'events' (TOF) | 'pixels' (TOA)
        self._lag_ms = None  # end-to-end latency (extraction -> GUI), updated per batch

        # Cross-thread signal helper
        self._serval_sig = _ServalSignaller()
        self._serval_sig.started.connect(self._on_serval_started)
        self._serval_sig.failed.connect(self._on_pipeline_error)

        # Timers
        self.refresh_timer = QTimer()
        self.refresh_timer.timeout.connect(self._update_histograms)

        self._save_timer = QTimer()
        self._save_timer.setSingleShot(True)
        self._save_timer.timeout.connect(self._auto_stop_save)

        self._last_clear_time = None

        # Build UI
        self._setup_toolbar()
        self._create_recording_toolbar()
        self._setup_ui()
        self._connect_signals()

        # Status bar
        self.status_bar = QStatusBar()
        self.setStatusBar(self.status_bar)
        self._build_status_leds()
        self.status_bar.showMessage("Ready")

        self._restore_session()

        # Keep toolbar toggles in sync when the recording toolbar is closed
        self._recording_toolbar.visibilityChanged.connect(
            lambda v: self.get_action('show_recording').setChecked(v))

