    # =========================================================================
    # Status bar LEDs
    # =========================================================================
    def _build_status_leds(self):
        for name, label in [('led_connected', 'SERVAL'),
                             ('led_acquiring', 'ACQ'),
                             ('led_recording', 'REC')]:
            led = QLabel(f'● {label}')
            led.setStyleSheet('color: #555555; font-weight: bold; padding: 0 6px;')
            self.status_bar.addPermanentWidget(led)
            setattr(self, name, led)

    def _set_led(self, led: QLabel, active: bool, color: str = '#44cc44'):
        col = color if active else '#555555'
        led.setStyleSheet(f'color: {col}; font-weight: bold; padding: 0 6px;')

